// appRoles section of the App Registration manifest
{
  "appRoles": [
    {
      "allowedMemberTypes": ["User", "Application"],
      "description": "Can read all reports",
      "displayName": "Report Reader",
      "id": "aaaabbbb-cccc-dddd-eeee-111111111111",
      "isEnabled": true,
      "value": "Reports.Read"
    },
    {
      "allowedMemberTypes": ["Application"],
      "description": "Service-to-service access — no user required",
      "displayName": "Data Ingestor",
      "id": "aaaabbbb-cccc-dddd-eeee-222222222222",
      "isEnabled": true,
      "value": "Data.Ingest"
    }
  ]
}

// Decoded access token claims when 'Data.Ingest' role is assigned
{
  "aud": "api://my-backend-api",
  "iss": "https://login.microsoftonline.com/<tenant-id>/v2.0",
  "oid": "<calling-service-principal-object-id>",
  "sub": "<calling-service-principal-object-id>",
  "appid": "<calling-app-client-id>",
  "roles": ["Data.Ingest"],
  "idtyp": "app"
}
// Your API validates 'roles' claim contains the required role before processing the request
